#include <cuda_runtime.h>
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <string.h>
#include <fcntl.h>
#include <unistd.h>

#define BIGRND 0x7fffffff
#define THREADS 256
#define ETA 0.3f
#define MOMENTUM 0.3f
#define ABS(x) (((x) > 0.0f) ? (x) : (-(x)))

typedef struct {
  int input_n;
  int hidden_n;
  int output_n;

  float *input_units;
  float *hidden_units;
  float *output_units;

  float *hidden_delta;
  float *output_delta;

  float *target;

  float **input_weights;
  float **hidden_weights;

  float **input_prev_weights;
  float **hidden_prev_weights;
} BPNN;

static int cuda_is_available() {
  static int initialized = 0;
  static int available = 0;
  if (!initialized) {
    int count = 0;
    cudaError_t err = cudaGetDeviceCount(&count);
    available = (err == cudaSuccess && count > 0) ? 1 : 0;
    initialized = 1;
  }
  return available;
}

static inline float squash_host(float x) {
  return 1.0f / (1.0f + expf(-x));
}

__device__ static inline float squash_device(float x) {
  return 1.0f / (1.0f + expf(-x));
}

extern "C" float squash(float x) {
  return squash_host(x);
}

extern "C" float drnd() {
  return ((float) rand() / (float) BIGRND);
}

extern "C" float dpn1() {
  return ((drnd() * 2.0f) - 1.0f);
}

extern "C" float *alloc_1d_dbl(int n) {
  float *newp = (float *) malloc((unsigned) (n * sizeof(float)));
  if (newp == NULL) {
    printf("ALLOC_1D_DBL: Couldn't allocate array of floats\n");
    return NULL;
  }
  return newp;
}

extern "C" float **alloc_2d_dbl(int m, int n) {
  int i;
  float **newp = (float **) malloc((unsigned) (m * sizeof(float *)));
  if (newp == NULL) {
    printf("ALLOC_2D_DBL: Couldn't allocate array of dbl ptrs\n");
    return NULL;
  }
  for (i = 0; i < m; i++) {
    newp[i] = alloc_1d_dbl(n);
  }
  return newp;
}

static void bpnn_randomize_weights(float **w, int m, int n) {
  for (int i = 0; i <= m; i++) {
    for (int j = 0; j <= n; j++) {
      w[i][j] = (float) rand() / RAND_MAX;
    }
  }
}

static void bpnn_randomize_row(float *w, int m) {
  for (int i = 0; i <= m; i++) {
    w[i] = 0.1f;
  }
}

static void bpnn_zero_weights(float **w, int m, int n) {
  for (int i = 0; i <= m; i++) {
    for (int j = 0; j <= n; j++) {
      w[i][j] = 0.0f;
    }
  }
}

extern "C" void bpnn_initialize(int seed) {
  printf("Random number generator seed: %d\n", seed);
  srand(seed);
}

static BPNN *bpnn_internal_create(int n_in, int n_hidden, int n_out) {
  BPNN *newnet = (BPNN *) malloc(sizeof(BPNN));
  if (newnet == NULL) {
    printf("BPNN_CREATE: Couldn't allocate neural network\n");
    return NULL;
  }

  newnet->input_n = n_in;
  newnet->hidden_n = n_hidden;
  newnet->output_n = n_out;
  newnet->input_units = alloc_1d_dbl(n_in + 1);
  newnet->hidden_units = alloc_1d_dbl(n_hidden + 1);
  newnet->output_units = alloc_1d_dbl(n_out + 1);

  newnet->hidden_delta = alloc_1d_dbl(n_hidden + 1);
  newnet->output_delta = alloc_1d_dbl(n_out + 1);
  newnet->target = alloc_1d_dbl(n_out + 1);

  newnet->input_weights = alloc_2d_dbl(n_in + 1, n_hidden + 1);
  newnet->hidden_weights = alloc_2d_dbl(n_hidden + 1, n_out + 1);

  newnet->input_prev_weights = alloc_2d_dbl(n_in + 1, n_hidden + 1);
  newnet->hidden_prev_weights = alloc_2d_dbl(n_hidden + 1, n_out + 1);

  return newnet;
}

extern "C" void bpnn_free(BPNN *net) {
  int n1 = net->input_n;
  int n2 = net->hidden_n;

  free((char *) net->input_units);
  free((char *) net->hidden_units);
  free((char *) net->output_units);

  free((char *) net->hidden_delta);
  free((char *) net->output_delta);
  free((char *) net->target);

  for (int i = 0; i <= n1; i++) {
    free((char *) net->input_weights[i]);
    free((char *) net->input_prev_weights[i]);
  }
  free((char *) net->input_weights);
  free((char *) net->input_prev_weights);

  for (int i = 0; i <= n2; i++) {
    free((char *) net->hidden_weights[i]);
    free((char *) net->hidden_prev_weights[i]);
  }
  free((char *) net->hidden_weights);
  free((char *) net->hidden_prev_weights);

  free((char *) net);
}

extern "C" BPNN *bpnn_create(int n_in, int n_hidden, int n_out) {
  BPNN *newnet = bpnn_internal_create(n_in, n_hidden, n_out);

#ifdef INITZERO
  bpnn_zero_weights(newnet->input_weights, n_in, n_hidden);
#else
  bpnn_randomize_weights(newnet->input_weights, n_in, n_hidden);
#endif
  bpnn_randomize_weights(newnet->hidden_weights, n_hidden, n_out);
  bpnn_zero_weights(newnet->input_prev_weights, n_in, n_hidden);
  bpnn_zero_weights(newnet->hidden_prev_weights, n_hidden, n_out);
  bpnn_randomize_row(newnet->target, n_out);
  return newnet;
}

static float *flatten_matrix(float **w, int m, int n) {
  int rows = m + 1;
  int cols = n + 1;
  size_t total = (size_t) rows * (size_t) cols;
  float *flat = (float *) malloc(total * sizeof(float));
  if (flat == NULL) return NULL;
  for (int i = 0; i <= m; i++) {
    for (int j = 0; j <= n; j++) {
      flat[(size_t) i * cols + j] = w[i][j];
    }
  }
  return flat;
}

static void unflatten_matrix(float **w, int m, int n, const float *flat) {
  int cols = n + 1;
  for (int i = 0; i <= m; i++) {
    for (int j = 0; j <= n; j++) {
      w[i][j] = flat[(size_t) i * cols + j];
    }
  }
}

static void bpnn_layerforward_cpu(float *l1, float *l2, float **conn, int n1, int n2) {
  l1[0] = 1.0f;
  for (int j = 1; j <= n2; j++) {
    float sum = 0.0f;
    for (int k = 0; k <= n1; k++) {
      sum += conn[k][j] * l1[k];
    }
    l2[j] = squash_host(sum);
  }
}

__global__ void layerforward_kernel(const float *l1, float *l2, const float *conn, int n1, int n2, int cols) {
  int j = blockIdx.x * blockDim.x + threadIdx.x + 1;
  if (j <= n2) {
    float sum = 0.0f;
    for (int k = 0; k <= n1; k++) {
      sum += conn[(size_t) k * cols + j] * l1[k];
    }
    l2[j] = squash_device(sum);
  }
}

extern "C" void bpnn_layerforward(float *l1, float *l2, float **conn, int n1, int n2) {
  l1[0] = 1.0f;

  if (!cuda_is_available()) {
    bpnn_layerforward_cpu(l1, l2, conn, n1, n2);
    return;
  }

  int rows = n1 + 1;
  int cols = n2 + 1;
  size_t l1_bytes = (size_t) (n1 + 1) * sizeof(float);
  size_t conn_bytes = (size_t) rows * (size_t) cols * sizeof(float);
  size_t l2_bytes = (size_t) (n2 + 1) * sizeof(float);

  float *h_conn = flatten_matrix(conn, n1, n2);
  if (h_conn == NULL) {
    bpnn_layerforward_cpu(l1, l2, conn, n1, n2);
    return;
  }

  float *d_l1 = NULL, *d_l2 = NULL, *d_conn = NULL;
  cudaError_t err = cudaSuccess;
  err = cudaMalloc((void **) &d_l1, l1_bytes);
  if (err == cudaSuccess) err = cudaMalloc((void **) &d_l2, l2_bytes);
  if (err == cudaSuccess) err = cudaMalloc((void **) &d_conn, conn_bytes);
  if (err == cudaSuccess) err = cudaMemcpy(d_l1, l1, l1_bytes, cudaMemcpyHostToDevice);
  if (err == cudaSuccess) err = cudaMemcpy(d_conn, h_conn, conn_bytes, cudaMemcpyHostToDevice);

  if (err != cudaSuccess) {
    if (d_l1) cudaFree(d_l1);
    if (d_l2) cudaFree(d_l2);
    if (d_conn) cudaFree(d_conn);
    free(h_conn);
    bpnn_layerforward_cpu(l1, l2, conn, n1, n2);
    return;
  }

  int blocks = (n2 + THREADS - 1) / THREADS;
  layerforward_kernel<<<blocks, THREADS>>>(d_l1, d_l2, d_conn, n1, n2, cols);
  err = cudaGetLastError();
  if (err == cudaSuccess) err = cudaDeviceSynchronize();
  if (err == cudaSuccess && n2 > 0) {
    err = cudaMemcpy(l2 + 1, d_l2 + 1, (size_t) n2 * sizeof(float), cudaMemcpyDeviceToHost);
  }

  cudaFree(d_l1);
  cudaFree(d_l2);
  cudaFree(d_conn);
  free(h_conn);

  if (err != cudaSuccess) {
    bpnn_layerforward_cpu(l1, l2, conn, n1, n2);
  }
}

extern "C" void bpnn_output_error(float *delta, float *target, float *output, int nj, float *err) {
  float errsum = 0.0f;
  for (int j = 1; j <= nj; j++) {
    float o = output[j];
    float t = target[j];
    delta[j] = o * (1.0f - o) * (t - o);
    errsum += ABS(delta[j]);
  }
  *err = errsum;
}

extern "C" void bpnn_hidden_error(float *delta_h, int nh, float *delta_o, int no, float **who, float *hidden, float *err) {
  float errsum = 0.0f;
  for (int j = 1; j <= nh; j++) {
    float h = hidden[j];
    float sum = 0.0f;
    for (int k = 1; k <= no; k++) {
      sum += delta_o[k] * who[j][k];
    }
    delta_h[j] = h * (1.0f - h) * sum;
    errsum += ABS(delta_h[j]);
  }
  *err = errsum;
}

static void bpnn_adjust_weights_cpu(float *delta, int ndelta, float *ly, int nly, float **w, float **oldw) {
  ly[0] = 1.0f;
  for (int j = 1; j <= ndelta; j++) {
    for (int k = 0; k <= nly; k++) {
      float new_dw = ((ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[k][j]));
      w[k][j] += new_dw;
      oldw[k][j] = new_dw;
    }
  }
}

__global__ void adjust_weights_kernel(const float *delta, int ndelta, const float *ly, int nly,
                                      float *w, float *oldw, int cols, int total) {
  int idx = blockIdx.x * blockDim.x + threadIdx.x;
  if (idx < total) {
    int k = idx / cols;
    int j = idx % cols;
    if (j >= 1 && j <= ndelta && k <= nly) {
      float new_dw = ((ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[idx]));
      w[idx] += new_dw;
      oldw[idx] = new_dw;
    }
  }
}

extern "C" void bpnn_adjust_weights(float *delta, int ndelta, float *ly, int nly, float **w, float **oldw) {
  ly[0] = 1.0f;

  if (!cuda_is_available()) {
    bpnn_adjust_weights_cpu(delta, ndelta, ly, nly, w, oldw);
    return;
  }

  int rows = nly + 1;
  int cols = ndelta + 1;
  int total = rows * cols;

  size_t delta_bytes = (size_t) (ndelta + 1) * sizeof(float);
  size_t ly_bytes = (size_t) (nly + 1) * sizeof(float);
  size_t mat_bytes = (size_t) total * sizeof(float);

  float *h_w = flatten_matrix(w, nly, ndelta);
  float *h_oldw = flatten_matrix(oldw, nly, ndelta);
  if (h_w == NULL || h_oldw == NULL) {
    if (h_w) free(h_w);
    if (h_oldw) free(h_oldw);
    bpnn_adjust_weights_cpu(delta, ndelta, ly, nly, w, oldw);
    return;
  }

  float *d_delta = NULL, *d_ly = NULL, *d_w = NULL, *d_oldw = NULL;
  cudaError_t err = cudaSuccess;
  err = cudaMalloc((void **) &d_delta, delta_bytes);
  if (err == cudaSuccess) err = cudaMalloc((void **) &d_ly, ly_bytes);
  if (err == cudaSuccess) err = cudaMalloc((void **) &d_w, mat_bytes);
  if (err == cudaSuccess) err = cudaMalloc((void **) &d_oldw, mat_bytes);
  if (err == cudaSuccess) err = cudaMemcpy(d_delta, delta, delta_bytes, cudaMemcpyHostToDevice);
  if (err == cudaSuccess) err = cudaMemcpy(d_ly, ly, ly_bytes, cudaMemcpyHostToDevice);
  if (err == cudaSuccess) err = cudaMemcpy(d_w, h_w, mat_bytes, cudaMemcpyHostToDevice);
  if (err == cudaSuccess) err = cudaMemcpy(d_oldw, h_oldw, mat_bytes, cudaMemcpyHostToDevice);

  if (err != cudaSuccess) {
    if (d_delta) cudaFree(d_delta);
    if (d_ly) cudaFree(d_ly);
    if (d_w) cudaFree(d_w);
    if (d_oldw) cudaFree(d_oldw);
    free(h_w);
    free(h_oldw);
    bpnn_adjust_weights_cpu(delta, ndelta, ly, nly, w, oldw);
    return;
  }

  int blocks = (total + THREADS - 1) / THREADS;
  adjust_weights_kernel<<<blocks, THREADS>>>(d_delta, ndelta, d_ly, nly, d_w, d_oldw, cols, total);
  err = cudaGetLastError();
  if (err == cudaSuccess) err = cudaDeviceSynchronize();
  if (err == cudaSuccess) err = cudaMemcpy(h_w, d_w, mat_bytes, cudaMemcpyDeviceToHost);
  if (err == cudaSuccess) err = cudaMemcpy(h_oldw, d_oldw, mat_bytes, cudaMemcpyDeviceToHost);

  cudaFree(d_delta);
  cudaFree(d_ly);
  cudaFree(d_w);
  cudaFree(d_oldw);

  if (err == cudaSuccess) {
    unflatten_matrix(w, nly, ndelta, h_w);
    unflatten_matrix(oldw, nly, ndelta, h_oldw);
  } else {
    bpnn_adjust_weights_cpu(delta, ndelta, ly, nly, w, oldw);
  }

  free(h_w);
  free(h_oldw);
}

extern "C" void bpnn_feedforward(BPNN *net) {
  int in = net->input_n;
  int hid = net->hidden_n;
  int out = net->output_n;

  bpnn_layerforward(net->input_units, net->hidden_units, net->input_weights, in, hid);
  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);
}

extern "C" void bpnn_train(BPNN *net, float *eo, float *eh) {
  int in = net->input_n;
  int hid = net->hidden_n;
  int out = net->output_n;
  float out_err, hid_err;

  bpnn_layerforward(net->input_units, net->hidden_units, net->input_weights, in, hid);
  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);

  bpnn_output_error(net->output_delta, net->target, net->output_units, out, &out_err);
  bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out, net->hidden_weights, net->hidden_units, &hid_err);
  *eo = out_err;
  *eh = hid_err;

  bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid, net->hidden_weights, net->hidden_prev_weights);
  bpnn_adjust_weights(net->hidden_delta, hid, net->input_units, in, net->input_weights, net->input_prev_weights);
}

extern "C" void bpnn_save(BPNN *net, char *filename) {
  int n1, n2, n3, i, j, memcnt;
  float dvalue, **w;
  char *mem;
  FILE *pFile = fopen(filename, "w+");

  n1 = net->input_n;
  n2 = net->hidden_n;
  n3 = net->output_n;
  printf("Saving %dx%dx%d network to '%s'\n", n1, n2, n3, filename);

  fwrite((char *) &n1, sizeof(char), sizeof(char), pFile);
  fwrite((char *) &n2, sizeof(char), sizeof(char), pFile);
  fwrite((char *) &n3, sizeof(char), sizeof(char), pFile);

  memcnt = 0;
  w = net->input_weights;
  size_t input_elems = (size_t) (n1 + 1) * (size_t) (n2 + 1);
  size_t input_alloc = input_elems * sizeof(float) * sizeof(float);
  mem = (char *) malloc((unsigned) input_alloc);
  for (i = 0; i <= n1; i++) {
    for (j = 0; j <= n2; j++) {
      dvalue = w[i][j];
      memcpy(&mem[memcnt], &dvalue, sizeof(float));
      memcnt += sizeof(float);
    }
  }
  fwrite(mem, (unsigned) (sizeof(float)), (unsigned) (input_elems * sizeof(float)), pFile);
  free(mem);

  memcnt = 0;
  w = net->hidden_weights;
  size_t hidden_elems = (size_t) (n2 + 1) * (size_t) (n3 + 1);
  size_t hidden_alloc = hidden_elems * sizeof(float) * sizeof(float);
  mem = (char *) malloc((unsigned) hidden_alloc);
  for (i = 0; i <= n2; i++) {
    for (j = 0; j <= n3; j++) {
      dvalue = w[i][j];
      memcpy(&mem[memcnt], &dvalue, sizeof(float));
      memcnt += sizeof(float);
    }
  }
  fwrite(mem, sizeof(float), (unsigned) (hidden_elems * sizeof(float)), pFile);
  free(mem);

  fclose(pFile);
}

extern "C" BPNN *bpnn_read(char *filename) {
  char *mem;
  BPNN *newnet;
  int fd, n1, n2, n3, i, j, memcnt;

  if ((fd = open(filename, 0, 0644)) == -1) {
    return NULL;
  }

  printf("Reading '%s'\n", filename);

  read(fd, (char *) &n1, sizeof(int));
  read(fd, (char *) &n2, sizeof(int));
  read(fd, (char *) &n3, sizeof(int));
  newnet = bpnn_internal_create(n1, n2, n3);

  printf("'%s' contains a %dx%dx%d network\n", filename, n1, n2, n3);
  printf("Reading input weights...");

  memcnt = 0;
  mem = (char *) malloc((unsigned) ((n1 + 1) * (n2 + 1) * sizeof(float)));
  read(fd, mem, (n1 + 1) * (n2 + 1) * sizeof(float));
  for (i = 0; i <= n1; i++) {
    for (j = 0; j <= n2; j++) {
      memcpy(&(newnet->input_weights[i][j]), &mem[memcnt], sizeof(float));
      memcnt += sizeof(float);
    }
  }
  free(mem);

  printf("Done\nReading hidden weights...");

  memcnt = 0;
  mem = (char *) malloc((unsigned) ((n2 + 1) * (n3 + 1) * sizeof(float)));
  read(fd, mem, (n2 + 1) * (n3 + 1) * sizeof(float));
  for (i = 0; i <= n2; i++) {
    for (j = 0; j <= n3; j++) {
      memcpy(&(newnet->hidden_weights[i][j]), &mem[memcnt], sizeof(float));
      memcnt += sizeof(float);
    }
  }
  free(mem);
  close(fd);

  printf("Done\n");

  bpnn_zero_weights(newnet->input_prev_weights, n1, n2);
  bpnn_zero_weights(newnet->hidden_prev_weights, n2, n3);

  return newnet;
}

